// Determine contact email based on direction
// FIX: normalize to lowercase to ensure consistent Mautic matching
const from = ($json.from || '').toLowerCase();
const to   = ($json.to   || '').toLowerCase();

const isIncoming   = !from.includes('@devreemakelaardij.nl');
const contactEmail = isIncoming ? from : to;
const direction    = isIncoming ? 'inkomend' : 'uitgaand';

return [{
  json: {
    ...($json),
    from,
    to,
    contactEmail,
    direction,
    isIncoming
  }
}];

// FIX: Notion query already filters Actief=true, redundant filter removed
const taxonomy = $input.all()
  .map(item => ({
    jsonPath: item.json.property_json_path || "",
    dataType: item.json.property_data_type || "",
    hint:     item.json.property_ollama_prompt_hint || ""
  }))
  .filter(f => f.jsonPath); // skip items without a path

// Bouw prompt hints
const promptSections = taxonomy
  .map(f => `- ${f.jsonPath} (${f.dataType}): ${f.hint}`)
  .join('\n');

// Bouw dynamisch JSON schema op basis van jsonPath
function buildSchema(fields) {
  const schema = {};
  fields.forEach(field => {
    const parts = field.jsonPath.split('.');
    let current = schema;
    for (let i = 0; i < parts.length; i++) {
      const part   = parts[i];
      const isLast = i === parts.length - 1;
      if (isLast) {
        switch (field.dataType) {
          case 'Score 0-100': current[part] = 0;     break;
          case 'Array':       current[part] = [];    break;
          case 'Object':      current[part] = {};    break;
          case 'Boolean':     current[part] = false; break;
          case 'Text':        current[part] = "";    break;
          default:            current[part] = null;
        }
      } else {
        if (!current[part]) current[part] = {};
        current = current[part];
      }
    }
  });
  return schema;
}

const jsonSchema    = buildSchema(taxonomy);
const systemPrompt  = `Je bent een data-extractie expert voor een makelaarskantoor.
Analyseer deze email en extract ALLEEN informatie waar je >70% zeker van bent.
Laat velden leeg/null als je niet zeker bent.

Te detecteren velden:
${promptSections}

Output ALLEEN valid JSON volgens exact dit schema (vul alleen in wat je detecteert):
${JSON.stringify(jsonSchema, null, 2)}`;

return [{ json: { systemPrompt, jsonSchema } }];

// Input is een array met lead objects
return $input.all().map(item => {
  const lead = item.json;

  if (!lead || !lead.id) {
    return {
      json: {
        contactId: null,
        contactExists: false,
        shouldCreateContact: true
      }
    };
  }

  return {
    json: {
      contactId:           Number(lead.id),
      contactExists:       true,
      shouldCreateContact: false,

      // FIX: normalize email to lowercase for consistent matching
      mautic_email:         (lead.fields?.all?.email || '').toLowerCase() || null,
      mautic_firstname:     lead.fields?.all?.firstname  || null,
      mautic_lastname:      lead.fields?.all?.lastname   || null,
      mautic_mobile:        lead.fields?.all?.mobile     || null,
      mautic_title:         lead.fields?.all?.title      || null,

      mautic_address1:      lead.fields?.all?.address1   || null,
      mautic_address2:      lead.fields?.all?.address2   || null,
      mautic_city:          lead.fields?.all?.city       || null,
      mautic_zipcode:       lead.fields?.all?.zipcode    || null,

      mautic_realworks_code: lead.fields?.all?.realworks_code || null,
      ai_profiel_data:       lead.fields?.all?.ai_profiel_data || null,

      points:       lead.points   || 0,
      dateAdded:    lead.dateAdded    || null,
      dateModified: lead.dateModified || null,
      lastActive:   lead.lastActive   || null
    }
  };
});

const mauticResponse = $input.first().json;

const newContactId =
  mauticResponse.id ||
  mauticResponse.contact?.id ||
  null;

const originalEmail = $('ContactEmail en incoming bepalen').item.json.contactEmail;

const points =
  mauticResponse.fields?.core?.points?.normalizedValue ||
  mauticResponse.points ||
  0;

return [{
  json: {
    contactId:             newContactId,
    // FIX: email already lowercase from ContactEmail node
    mautic_email:          originalEmail,
    mautic_firstname:      null,
    mautic_lastname:       originalEmail.split('@')[0],
    mautic_mobile:         null,
    mautic_realworks_code: null,
    ai_profiel_data:       null,
    points,
    contactExists:         false
  }
}];

return $input.all().map(item => {
  const date = new Date(item.json.receivedDate).toLocaleString('nl-NL', {
    day:    '2-digit',
    month:  '2-digit',
    year:   'numeric',
    hour:   '2-digit',
    minute: '2-digit'
  });

  // FIX: removed manual quote-escaping — n8n serializes JSON body automatically
  const cleanBody = (item.json.bodyText || '')
    .replace(/\\r\\n/g, '\n')
    .replace(/\n{3,}/g, '\n\n')
    .trim();

  const noteText =
`📧 Email ${item.json.direction === 'inkomend' ? 'ontvangen' : 'verzonden'} - ${date}

Van: ${item.json.from}
Aan: ${item.json.to}
Onderwerp: ${item.json.subject}

${cleanBody}`;

  return {
    json: {
      lead: item.json.contactId,
      text: noteText,
      type: "email"
    }
  };
});

const items = $input.all().map(i => i.json);

const takenRes = items.find(x => Array.isArray(x.tasks))    || {};
const projRes  = items.find(x => Array.isArray(x.projects)) || {};

const tasks    = Array.isArray(takenRes.tasks)    ? takenRes.tasks    : [];
const projects = Array.isArray(projRes.projects)  ? projRes.projects  : [];

const projectsCompact = projects.map(p => ({
  id:         p.id,
  name:       p.name,
  status:     p.status,
  tasksCount: p._count?.tasks ?? null,
  callsCount: p._count?.calls ?? null,
}));

const projectById = Object.fromEntries(projectsCompact.map(p => [p.id, p]));

const tasksCompact = tasks.map(t => ({
  id:          t.id,
  title:       t.title,
  status:      t.status,
  priority:    t.priority    ?? null,
  dueDate:     t.dueDate     ?? null,
  category:    t.category    ?? null,
  assigneeId:  t.assigneeId  ?? null,
  projectId:   t.projectId   ?? null,
  projectName: t.projectId ? (projectById[t.projectId]?.name ?? null) : null,
}));

return [
  {
    json: {
      ai_context: {
        open_tasks: tasksCompact,
        projects:   projectsCompact,
        rules: {
          project_linking: "Kies alleen een projectId uit projects[] als de titel/omschrijving daar sterk op matcht. Anders laat projectId leeg.",
          updates: "Bij afronden: gebruik task_ops met op:'update', id:'...', status:'afgerond'."
        }
      }
    }
  }
];

const all = $input.all().map(i => i.json);

// Merge3 (combineAll) levert 1 item met alle velden samen:
// - systemPrompt + jsonSchema (van Notion pad)
// - email/contact velden (van Merge enrichInput2 pad)
// - ai_context (van taken/projecten pad)

// Vind het item met de meeste bruikbare velden
const main =
  all.find(x => typeof x.systemPrompt === 'string' && x.subject && x.bodyText) ||
  all.find(x => typeof x.systemPrompt === 'string') ||
  all[0];

const ctxItem  = all.find(x => x.ai_context) || {};
const ai_context = ctxItem.ai_context || {};

const emailText =
`Van: ${main.from || ''}
Aan: ${main.to || ''}
Onderwerp: ${main.subject || ''}
Datum: ${main.receivedDate || ''}

${main.bodyText || ''}`;

return {
  json: {
    systemPrompt: main.systemPrompt || '',
    rawText:      emailText,

    contactFields: {
      ai_profiel_data: main.ai_profiel_data || null,
    },

    ai_context: {
      open_tasks: Array.isArray(ai_context.open_tasks) ? ai_context.open_tasks : [],
      projects:   Array.isArray(ai_context.projects)   ? ai_context.projects   : [],
      rules:      ai_context.rules || {},
    },

    contactId:    main.contactId    ?? null,
    contactEmail: main.contactEmail || main.mautic_email || null,
    // FIX: forward points zodat Code in JavaScript1 kan optellen
    points:       main.points       ?? 0,
  },
};

const aiOutput   = $json.text;
const contactId  = $json.contactId  ?? null;
// FIX: points nu correct doorgestuurd via Format Data voor LLM1
const oldPoints  = $json.points     ?? 0;
const lastActive = new Date().toISOString();

// Strip markdown code fences als de LLM die toch meestuurt
let cleaned = aiOutput
  .replace(/^`+(json)?\s*/i, '')
  .replace(/\s*`+$/i,        '')
  .trim();

let parsed;
try {
  parsed = JSON.parse(cleaned);
} catch (e) {
  const match = cleaned.match(/\{[\s\S]*\}/);
  if (!match) throw new Error(`LLM output is geen geldige JSON: ${cleaned.slice(0, 200)}`);
  parsed = JSON.parse(match[0]);
}

const profiel  = parsed.profiel   ?? parsed;
const task_ops = Array.isArray(parsed.task_ops) ? parsed.task_ops : [];

// Points berekenen
const engagementLevel = profiel.conversatie_stats?.engagement_level || '';
let pointsToAdd = 0;
switch (String(engagementLevel).toLowerCase()) {
  case 'hoog':     case 'high':   pointsToAdd = 10; break;
  case 'gemiddeld': case 'medium': pointsToAdd =  5; break;
  case 'laag':     case 'low':    pointsToAdd =  2; break;
  default: pointsToAdd = 0;
}

const interesses = profiel.interesses || {};
// FIX: points cap om onbegrensde groei te voorkomen
const totalPoints = Math.min(oldPoints + pointsToAdd, 1000);

return {
  json: {
    success:   true,
    contactId,
    ai_profiel_data: JSON.stringify(profiel),
    task_ops,
    points:      totalPoints,
    last_active: lastActive,

    interesse_financiering:  interesses.financiering   || 0,
    interesse_duurzaamheid:  interesses.duurzaamheid   || 0,
    interesse_verbouwing:    interesses.verbouwing     || 0,
    interesse_investeren:    interesses.investeren     || 0,
    interesse_starters:      interesses.starters_info  || 0,
  }
};

const input = $json;

const taskOps = Array.isArray(input.task_ops) ? input.task_ops : [];
if (taskOps.length === 0) return [];

const ASSIGNEE_EMAIL = {
  "Melvin de Vree":  "melvin@devreemakelaardij.nl",
  "Algemeen":        "info@devreemakelaardij.nl",
  "Anja de Vree":    "info@devreemakelaardij.nl",
  "Trudie Verduin":  "info@devreemakelaardij.nl",
  "Erling de Vree":  "info@devreemakelaardij.nl",
};

const defaultDue = new Date();
defaultDue.setDate(defaultDue.getDate() + 2);

const payloads = [];

for (const op of taskOps) {
  if (op.op === "create") {
    payloads.push({
      action:        "create",
      title:         op.title,
      description:   op.description   ?? null,
      priority:      op.priority      ?? "normaal",
      category:      op.category      ?? "administratie",
      dueDate:       op.dueDate
                       ? new Date(op.dueDate).toISOString()
                       : defaultDue.toISOString(),
      assigneeEmail: ASSIGNEE_EMAIL[op.assignee] || ASSIGNEE_EMAIL["Algemeen"],
      projectId:     op.projectId ?? undefined,
      contactId:     input.contactId ?? null,
      notionPageId:  null,
    });
  }

  if (op.op === "update") {
    const body = {
      action: "update",
      ...(op.id           ? { id: op.id }                     : {}),
      ...(op.notionPageId ? { notionPageId: op.notionPageId } : {}),
    };

    if (!body.id && !body.notionPageId) continue;

    if (op.status      !== undefined) body.status      = op.status;
    if (op.title       !== undefined) body.title       = op.title;
    if (op.description !== undefined) body.description = op.description;
    if (op.priority    !== undefined) body.priority    = op.priority;
    if (op.category    !== undefined) body.category    = op.category;
    if (op.dueDate     !== undefined) body.dueDate     = op.dueDate ? new Date(op.dueDate).toISOString() : null;
    if (op.projectId   !== undefined) body.projectId   = op.projectId;
    if (op.assignee)                  body.assigneeEmail = ASSIGNEE_EMAIL[op.assignee] || ASSIGNEE_EMAIL["Algemeen"];

    payloads.push(body);
  }
}

return payloads.map(p => ({ json: p }));
